import { hdf5Cat, type PathSpec, type RegisteredOp, ResourceName } from '@struktoai/mirage-core'
import type { DiskAccessor } from '../../accessor/disk.ts'
import { read as coreRead } from '../../core/disk/read.ts'

export const readHdf5Op: RegisteredOp = {
  name: 'read',
  resource: ResourceName.DISK,
  filetype: '.hdf5',
  write: false,
  fn: async (accessor: DiskAccessor, path: PathSpec) => {
    const raw = await coreRead(accessor, path)
    return hdf5Cat(raw)
  },
}
